'use client';
import React, { useState } from 'react';

export default function ContactSection() {
      const [form, setForm] = useState({ name: '', email: '', message: '' });
        const [status, setStatus] = useState<'idle' | 'sending' | 'sent' | 'error'>('idle');

          const handle = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) =>
              setForm({ ...form, [e.target.name]: e.target.value });

                const submit = async (e: React.FormEvent) => {
                        e.preventDefault();
                            setStatus('sending');
                                try {
                                          const res = await fetch('/api/contact', {
                                                    method: 'POST',
                                                            headers: { 'Content-Type': 'application/json' },
                                                                    body: JSON.stringify(form),
                                          });
                                                setStatus(res.ok ? 'sent' : 'error');
                                } catch {
                                          setStatus('error');
                                }
                                  };

                                    return (
                                        <section id="contact" className="py-24 px-6">
                                                  <div className="max-w-2xl mx-auto">
                                                            <div className="text-center mb-12">
                                                                          <p className="text-xs tracking-widest uppercase mb-4 font-semibold" style={{ color: '#14b8a6' }}>
                                                                                        Get In Touch
                                                                                                  </p>
                                                                                                            <h2
                                                                                                                        className="font-black mb-4"
                                                                                                                                    style={{ fontSize: 'clamp(28px,4vw,48px)', color: '#f0eaf8' }}
                                                                                                                                              >
                                                                                                                                                          Send Emily a Message
                                                                                                                                                                    </h2>
                                                                                                                                                                              <hr className="divider-brand" />
                                                                                                                                                                                        <p className="mt-4 text-base leading-relaxed" style={{ color: '#a9a3b8' }}>
                                                                                                                                                                                                        Questions about services, mobile visits, or scheduling? Emily will respond within 24 hours.
                                                                                                                                                                                                                  </p>
                                                                                                                                                                                                                          </div>

                                                                                                                                                                                                                                  {status === 'sent' ? (
                                                                                                                                                                                                                                              <div className="glass-purple rounded-2xl p-10 text-center animate-pulse-glow">
                                                                                                                                                                                                                                                            <div className="text-4xl mb-4">💜</div>
                                                                                                                                                                                                                                                                        <h3 className="text-xl font-bold mb-2" style={{ color: '#f0eaf8' }}>
                                                                                                                                                                                                                                                                                          Message received!
                                                                                                                                                                                                                                                                                                      </h3>
                                                                                                                                                                                                                                                                                                                  <p style={{ color: '#a9a3b8' }}>Emily will be in touch within 24 hours.</p>
                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                  ) : (
                                                                                                                                                                                                                                              <form onSubmit={submit} className="glass rounded-2xl p-8" style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                                                                                                                                                                                                                                                            <div>
                                                                                                                                                                                                                                                                              <label
                                                                                                                                                                                                                                                                                              className="block text-xs tracking-widest uppercase mb-2 font-semibold"
                                                                                                                                                                                                                                                                                                              style={{ color: '#a9a3b8' }}
                                                                                                                                                                                                                                                                                                                            >
                                                                                                                                                                                                                                                                                                                                                Name
                                                                                                                                                                                                                                                                                                                                                              </label>
                                                                                                                                                                                                                                                                                                                                                                            <input
                                                                                                                                                                                                                                                                                                                                                                                            name="name"
                                                                                                                                                                                                                                                                                                                                                                                                            value={form.name}
                                                                                                                                                                                                                                                                                                                                                                                                                            onChange={handle}
                                                                                                                                                                                                                                                                                                                                                                                                                                            placeholder="Your name"
                                                                                                                                                                                                                                                                                                                                                                                                                                                            style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  width: '100%',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    background: '#27273a',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      border: '1px solid #3b3a52',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        borderRadius: '10px',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          padding: '12px 14px',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            color: '#f0eaf8',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              fontSize: '14px',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                outline: 'none',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  boxSizing: 'border-box',
                                                                                                                                                                                                                                                                                                                                                                                                                                                            }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                          />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <label
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  className="block text-xs tracking-widest uppercase mb-2 font-semibold"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  style={{ color: '#a9a3b8' }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    Email *
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                name="email"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                value={form.email}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                onChange={handle}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                required
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                type="email"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                placeholder="your@email.com"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      width: '100%',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        background: '#27273a',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          border: '1px solid #3b3a52',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            borderRadius: '10px',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              padding: '12px 14px',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                color: '#f0eaf8',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  fontSize: '14px',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    outline: 'none',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      boxSizing: 'border-box',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <label
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      className="block text-xs tracking-widest uppercase mb-2 font-semibold"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      style={{ color: '#a9a3b8' }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    Message *
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <textarea
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                name="message"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                value={form.message}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                onChange={handle}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                required
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                rows={5}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                placeholder="Tell Emily what you're looking for…"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  width: '100%',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    background: '#27273a',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      border: '1px solid #3b3a52',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        borderRadius: '10px',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          padding: '12px 14px',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            color: '#f0eaf8',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              fontSize: '14px',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                outline: 'none',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  resize: 'vertical',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    boxSizing: 'border-box',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {status === 'error' && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <p style={{ color: '#f87171', fontSize: '13px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        Something went wrong. Please call (613) 929-8711 instead.
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            type="submit"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          disabled={status === 'sending'}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        className="btn-cta"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      style={{ opacity: status === 'sending' ? 0.6 : 1, width: '100%' }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {status === 'sending' ? 'Sending…' : 'Send Message'}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </form>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </section>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
